//////////////////////////////////////////////////////////////////////
//
//  VCMIntegrator.h - Vertex Connection and Merging integrator
//    (Georgiev et al., SIGGRAPH Asia 2012).
//
//    Implementation strategy:
//      - Subpaths are generated by BDPTIntegrator::GenerateLightSubpath
//        / GenerateEyeSubpath verbatim so all media / BSSRDF /
//        delta / dispersion handling stays in one place.
//      - VCM derives the per-vertex SmallVCM running quantities
//        (dVCM/dVC/dVM) in a post-walk over the BDPTVertex arrays,
//        using the emissionPdfW and cosAtGen fields that BDPT now
//        writes during generation.
//      - A LightVertexStore holds all non-delta surface vertices
//        from the full light pass, balanced into a KD-tree for
//        fixed-radius queries during the eye pass.
//      - VC strategies (s=0, s=1, t=1, interior) use the same
//        SmallVCM balance-heuristic weight as the merging strategy,
//        so both live in one MIS denominator.
//
//    Step 0 ships the class shell and empty methods so the build
//    wiring compiles end-to-end.  Steps 2-10 add the math.
//
//  Author: Aravind Krishnaswamy
//  Date of Birth: April 14, 2026
//  Tabs: 4
//  Comments:
//
//  License Information: Please see the attached LICENSE.TXT file
//
//////////////////////////////////////////////////////////////////////

#ifndef VCM_INTEGRATOR_
#define VCM_INTEGRATOR_

#include "../Interfaces/IReference.h"
#include "../Utilities/Reference.h"
#include "VCMRecurrence.h"
#include "VCMLightVertex.h"
#include "VCMLightVertexStore.h"
#include "BDPTIntegrator.h"

#include <vector>

namespace RISE
{
	class IScene;
	class IRayCaster;
	class ICamera;
	class IPixelFilter;

	namespace Implementation
	{
		class LightSampler;
		class SplatFilm;

		class VCMIntegrator :
			public virtual IReference,
			public virtual Reference
		{
		protected:
			virtual ~VCMIntegrator();

			/// BDPT integrator used as the subpath generator; VCM
			/// reuses its Generate{Light,Eye}Subpath entrypoints.
			BDPTIntegrator*				pGenerator;

			unsigned int				maxEyeDepth;
			unsigned int				maxLightDepth;
			StabilityConfig				stabilityConfig;

			/// User-requested merge radius.  0 => scene-auto fallback
			/// is resolved at render time from the scene bounds.
			Scalar						requestedMergeRadius;

			/// Enable vertex connection and vertex merging strategy
			/// classes respectively.  Both on by default.
			bool						enableVC;
			bool						enableVM;

		public:
			VCMIntegrator(
				const unsigned int maxEyeDepth_,
				const unsigned int maxLightDepth_,
				const Scalar requestedMergeRadius_,
				const bool enableVC_,
				const bool enableVM_,
				const StabilityConfig& stabilityConfig_
				);

			void SetLightSampler( const LightSampler* pLS );

			BDPTIntegrator* GetGenerator() const { return pGenerator; }

			unsigned int GetMaxEyeDepth() const { return maxEyeDepth; }
			unsigned int GetMaxLightDepth() const { return maxLightDepth; }
			Scalar GetRequestedMergeRadius() const { return requestedMergeRadius; }
			bool GetEnableVC() const { return enableVC; }
			bool GetEnableVM() const { return enableVM; }

			/// Walk a generated BDPT light subpath and derive the
			/// per-vertex SmallVCM running quantities (dVCM, dVC,
			/// dVM).  Non-delta surface vertices are appended to
			/// 'out' as lean LightVertex records ready for the
			/// LightVertexStore.  The medium-vertex branch is
			/// correctly traversed for the recurrence but no
			/// LightVertex is emitted (surface-only merging in v1).
			///
			/// Static so the math is free of implicit instance state
			/// — makes the function fully unit-testable against
			/// synthetic BDPTVertex arrays without constructing a
			/// VCMIntegrator.
			static void ConvertLightSubpath(
				const std::vector<BDPTVertex>& verts,
				const VCMNormalization& norm,
				std::vector<LightVertex>& out,
				std::vector<VCMMisQuantities>* outMis = 0
				);

			/// Walk a generated BDPT eye subpath and derive the
			/// per-vertex SmallVCM running quantities (dVCM, dVC,
			/// dVM).  Unlike the light side, eye vertices are
			/// consumed in-pixel and never persisted, so this
			/// overload emits one VCMMisQuantities per BDPTVertex
			/// (parallel array, same size, same indexing).  Each
			/// entry holds the state AFTER the geometric update at
			/// that vertex and BEFORE the BSDF-sampling update that
			/// prepares for the next vertex — the same convention
			/// as the light side and the same state SmallVCM reads
			/// at connection / merge time.
			///
			/// For the camera endpoint (index 0) we use InitCamera
			/// with cameraPdfW = v[0].emissionPdfW.  The first
			/// bounce always applies the distance-squared term to
			/// dVCM because the camera is a finite point.
			static void ConvertEyeSubpath(
				const std::vector<BDPTVertex>& verts,
				const VCMNormalization& norm,
				std::vector<VCMMisQuantities>& outMis
				);

			/// Strategy (s=0): eye subpath's tail vertex directly
			/// hits an emitter surface.  Iterates every non-delta
			/// SURFACE eye vertex at t>=2, tests if its material
			/// carries an IEmitter, computes Le toward the previous
			/// vertex, and weights using the SmallVCM formula:
			///
			///   wCamera = directPdfA * C.dVCM + emissionPdfW * C.dVC
			///   w       = 1 / (1 + wCamera)
			///   L      += v[t-1].throughput * Le * w
			///
			/// Where directPdfA is the AREA-measure pdf that the
			/// eye-side NEE process would have sampled this emitter
			/// position (pdfSelect * 1/area), and emissionPdfW is
			/// the combined area+solid-angle emission pdf matching
			/// what BDPT stores on light-endpoint vertices.
			RISEPel EvaluateS0(
				const IScene& scene,
				const IRayCaster& caster,
				const std::vector<BDPTVertex>& eyeVerts,
				const std::vector<VCMMisQuantities>& eyeMis,
				const VCMNormalization& norm
				) const;

			/// Strategy (s=1, t>=2): per-vertex next-event estimation.
			/// For each non-delta SURFACE eye vertex at index i>=1,
			/// samples a fresh light via the caster's light sampler,
			/// shadow-tests the connection, evaluates the BSDF at the
			/// eye vertex, and weights using the SmallVCM NEE formula:
			///
			///   wLight  = bsdfDirPdfW / (lightPickProb * directPdfW)
			///   wCamera = (emissionPdfW * cosToLight)
			///             / (directPdfW * cosAtLight)
			///           * (mMisVmWeightFactor
			///              + C.dVCM
			///              + C.dVC * bsdfRevPdfW)
			///   w       = 1 / (wLight + 1 + wCamera)
			RISEPel EvaluateNEE(
				const IScene& scene,
				const IRayCaster& caster,
				ISampler& sampler,
				const std::vector<BDPTVertex>& eyeVerts,
				const std::vector<VCMMisQuantities>& eyeMis,
				const VCMNormalization& norm
				) const;

			/// Strategy (s>=1, t=1): every non-delta light-subpath
			/// vertex connects directly to the camera via a splat.
			///
			/// For each non-delta vertex, computes a projected pixel
			/// position via BDPTCameraUtilities::Rasterize, tests
			/// visibility, evaluates fLight * We * G, and writes
			/// the MIS-weighted contribution to the splat film.
			///
			/// Because the light subpath's recurrence state is
			/// needed for the weight, this takes a parallel
			/// VCMMisQuantities array produced alongside
			/// ConvertLightSubpath rather than re-walking the
			/// recurrence.  ConvertLightSubpath's overload emits
			/// this array via 'outMis'.
			void SplatLightSubpathToCamera(
				const std::vector<BDPTVertex>& lightVerts,
				const std::vector<VCMMisQuantities>& lightMis,
				const IScene& scene,
				const IRayCaster& caster,
				const ICamera& camera,
				SplatFilm& splatFilm,
				const VCMNormalization& norm,
				const IPixelFilter* pixelFilter	///< [in] Reconstruction kernel; null = round-to-nearest point splat
				) const;

			/// Strategy (s>=2, t>=2): interior vertex connection.
			/// For every pair of non-delta surface vertices on the
			/// light and eye subpaths, attempts a connection:
			/// visibility test, evaluate both BSDFs, compute G,
			/// weight via the SmallVCM interior formula and
			/// accumulate into the per-pixel sampleColor.  Called
			/// once per pixel from VCMPelRasterizer::IntegratePixel.
			RISEPel EvaluateInteriorConnections(
				const IScene& scene,
				const IRayCaster& caster,
				const std::vector<BDPTVertex>& lightVerts,
				const std::vector<VCMMisQuantities>& lightMis,
				const std::vector<BDPTVertex>& eyeVerts,
				const std::vector<VCMMisQuantities>& eyeMis,
				const VCMNormalization& norm
				) const;

			/// Strategy (vertex merging): for each non-delta surface
			/// eye vertex, query the light vertex store within
			/// mMergeRadius, evaluate the eye vertex's BSDF in the
			/// direction of each candidate's incoming direction, and
			/// accumulate the SmallVCM-weighted merge contribution:
			///
			///   wLight  = L.dVCM * mMisVcWeightFactor
			///           + L.dVM * cameraBsdfDirPdfW
			///   wCamera = C.dVCM * mMisVcWeightFactor
			///           + C.dVM * cameraBsdfRevPdfW
			///   w       = 1 / (wLight + 1 + wCamera)
			///   contrib += w * cameraBsdf * L.throughput
			///
			/// After the inner loop over candidates, the total is
			/// scaled by mVmNormalization and by the eye vertex's
			/// throughput.  Callers pass an already-built store so
			/// this function can be invoked concurrently across
			/// many pixels once the light pass has finished.
			RISEPel EvaluateMerges(
				const std::vector<BDPTVertex>& eyeVerts,
				const std::vector<VCMMisQuantities>& eyeMis,
				const LightVertexStore& store,
				const VCMNormalization& norm
				) const;

			//////////////////////////////////////////////////////////////
			// Spectral (NM) variants — mirror the Pel evaluators but
			// operate on a single wavelength at a time.  Each returns
			// a Scalar radiance estimate; the caller converts to XYZ
			// via ColorUtils::XYZFromNM.  Note the recurrence itself
			// (VCMMisQuantities / ConvertLightSubpath / ConvertEyeSubpath)
			// is wavelength-independent and is reused verbatim from the
			// Pel side.
			//////////////////////////////////////////////////////////////

			Scalar EvaluateS0NM(
				const IScene& scene,
				const IRayCaster& caster,
				const std::vector<BDPTVertex>& eyeVerts,
				const std::vector<VCMMisQuantities>& eyeMis,
				const VCMNormalization& norm,
				const Scalar nm
				) const;

			Scalar EvaluateNEENM(
				const IScene& scene,
				const IRayCaster& caster,
				ISampler& sampler,
				const std::vector<BDPTVertex>& eyeVerts,
				const std::vector<VCMMisQuantities>& eyeMis,
				const VCMNormalization& norm,
				const Scalar nm
				) const;

			void SplatLightSubpathToCameraNM(
				const std::vector<BDPTVertex>& lightVerts,
				const std::vector<VCMMisQuantities>& lightMis,
				const IScene& scene,
				const IRayCaster& caster,
				const ICamera& camera,
				SplatFilm& splatFilm,
				const VCMNormalization& norm,
				const Scalar nm,
				const IPixelFilter* pixelFilter	///< [in] Reconstruction kernel; null = round-to-nearest point splat
				) const;

			Scalar EvaluateInteriorConnectionsNM(
				const IScene& scene,
				const IRayCaster& caster,
				const std::vector<BDPTVertex>& lightVerts,
				const std::vector<VCMMisQuantities>& lightMis,
				const std::vector<BDPTVertex>& eyeVerts,
				const std::vector<VCMMisQuantities>& eyeMis,
				const VCMNormalization& norm,
				const Scalar nm
				) const;

			Scalar EvaluateMergesNM(
				const std::vector<BDPTVertex>& eyeVerts,
				const std::vector<VCMMisQuantities>& eyeMis,
				const LightVertexStore& store,
				const VCMNormalization& norm,
				const Scalar nm
				) const;
		};
	}
}

#endif
